(function(w){"use strict";const ID="quadratic-equation";function compute(x){const a=Number(x.a),b=Number(x.b),c=Number(x.c);if(!Number.isFinite(a)||!Number.isFinite(b)||!Number.isFinite(c))return{error:"a, b, c에 숫자를 입력해 주세요."};if(a===0){if(b===0&&c===0)return{type:"infinite",label:"모든 실수가 해입니다."};if(b===0)return{type:"none",label:"해가 없습니다."};return{type:"linear",x:-c/b}}let d=b*b-4*a*c;const scale=Math.max(1,Math.abs(b*b),Math.abs(4*a*c)),tol=Number.EPSILON*scale*16;if(Math.abs(d)<=tol)d=0;if(d===0){const r=-b/(2*a);return{type:"double",discriminant:0,root1:r,root2:r}}if(d>0){const s=Math.sqrt(d);let q=-0.5*(b+(b>=0?s:-s));let r1,r2;if(q===0){r1=(-b+s)/(2*a);r2=(-b-s)/(2*a)}else{r1=q/a;r2=c/q}if(r1>r2){const t=r1;r1=r2;r2=t}return{type:"real",discriminant:d,root1:r1,root2:r2}}const real=-b/(2*a),imag=Math.sqrt(-d)/(2*Math.abs(a));return{type:"complex",discriminant:d,real,imag}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><p class="hm-calc-hint">ax² + bx + c = 0의 근을 계산합니다.</p><div class="hm-calc-grid-2"><div class="hm-calc-field"><label for="hm-quad-a">a</label><input id="hm-quad-a" class="hm-calc-input" inputmode="decimal" placeholder="예: 1"></div><div class="hm-calc-field"><label for="hm-quad-b">b</label><input id="hm-quad-b" class="hm-calc-input" inputmode="decimal" placeholder="예: -5"></div><div class="hm-calc-field"><label for="hm-quad-c">c</label><input id="hm-quad-c" class="hm-calc-input" inputmode="decimal" placeholder="예: 6"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">근 계산하기</button><button type="button" class="hm-calc-btn secondary">초기화</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const [a,b,c]=root.querySelectorAll("input"),[go,reset]=root.querySelectorAll("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({a:a.value,b:b.value,c:c.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");let value,detail="";if(r.type==="real"||r.type==="double"){value=`x₁ = ${api.formatNumber(r.root1,12)}<br>x₂ = ${api.formatNumber(r.root2,12)}`;detail=`<dl><dt>판별식</dt><dd>${api.formatNumber(r.discriminant,12)}</dd></dl>`}else if(r.type==="complex"){const sign=r.imag>=0?"+":"-",im=api.formatNumber(Math.abs(r.imag),12);value=`x₁ = ${api.formatNumber(r.real,12)} ${sign} ${im}i<br>x₂ = ${api.formatNumber(r.real,12)} - ${im}i`;detail=`<dl><dt>판별식</dt><dd>${api.formatNumber(r.discriminant,12)}</dd></dl>`}else if(r.type==="linear")value=`x = ${api.formatNumber(r.x,12)}`;else value=r.label;api.setResult(res,api.resultCard("방정식의 해",value,detail));});reset.addEventListener("click",()=>{a.value=b.value=c.value="";api.setMessage(msg,"");api.clearResult(res);a.focus();});}w.HM_CALC.register(ID,{compute,render});})(window);
